/* SweetAlert2 - Beautiful Alerts & Dialogs */
/* Uses CDN with fallback */

if (!window.Swal) {
  console.log('[SweetAlert2] Loading from CDN...');
  var script = document.createElement('script');
  script.src = 'https://cdn.jsdelivr.net/npm/sweetalert2@11.10.0/dist/sweetalert2.min.js';
  script.async = true;
  script.onerror = function() {
    console.warn('[SweetAlert2] CDN load failed');
    window.Swal = {
      fire: (config) => { alert(config.title); return Promise.resolve(); },
      close: () => {},
      showLoading: () => {}
    };
  };
  document.head.appendChild(script);
}
